import os
import json
from datetime import datetime, timedelta

class APICache:
    def __init__(self, cache_dir='api_cache', expire_hours=24):
        self.cache_dir = cache_dir
        self.expire_hours = expire_hours
        if not os.path.exists(cache_dir):
            os.makedirs(cache_dir)

    def _get_cache_path(self, key):
        return os.path.join(self.cache_dir, f"{key}.json")

    def is_expired(self, timestamp_str):
        timestamp = datetime.fromisoformat(timestamp_str)
        current_time = datetime.now()
        return (current_time - timestamp) > timedelta(hours=self.expire_hours)

    def get(self, key):
        cache_path = self._get_cache_path(key)
        if os.path.exists(cache_path):
            with open(cache_path, 'r') as file:
                data = json.load(file)
                if not self.is_expired(data['timestamp']):
                    return data['response']
        return None

    def set(self, key, response):
        cache_path = self._get_cache_path(key)
        timestamp = datetime.now().isoformat()
        with open(cache_path, 'w') as file:
            json.dump({'response': response, 'timestamp': timestamp}, file)

